const { parseDuration } = require('./src/core/duration.js');
const cases = [
  ['1h30m', 5400000],
  ['500ms', 500],
  ['250', 250],
  ['30s', 30000],
  ['1d', 86400000],
  ['1h30m15s', 5415000],
  ['100ms', 100],
  ['2m', 120000],
];
let ok = true;
for (const [input, expected] of cases) {
  const got = parseDuration(input);
  const pass = got === expected;
  if (!pass) ok = false;
  console.log((pass ? 'PASS' : 'FAIL') + ' parseDuration(' + JSON.stringify(input) + ') = ' + got + (pass ? '' : ' (expected ' + expected + ')'));
}
// Error cases
try { parseDuration('abc'); console.log('FAIL should have thrown for abc'); ok = false; } catch { console.log('PASS throws on abc'); }
try { parseDuration('1h2x'); console.log('FAIL should have thrown for 1h2x'); ok = false; } catch { console.log('PASS throws on 1h2x'); }
try { parseDuration(''); console.log('FAIL should have thrown for empty'); ok = false; } catch { console.log('PASS throws on empty'); }
console.log(ok ? 'ALL PASS' : 'SOME FAILED');
